//! Color + transform: RGB24->YUV420p (BT.601) + H.264 4x4 integer transform/quant
//! (+ inverses, for the compressed-intra path).
//!
//! Pure Rust, std+alloc only, no external crates, no threads — wasm32-safe.

// ─────────────────────────────────────────────────────────────────────────────
// PRIORITY 1 — RGB24 → YUV420p  (BT.601 limited / studio range)
// ─────────────────────────────────────────────────────────────────────────────

/// Convert packed RGB24 (R,G,B per pixel, row-major, length = w*h*3) to
/// planar YUV420p using BT.601 limited-range (studio swing) coefficients.
///
/// Returns `(Y, U, V)` where
///   - `Y.len() == w * h`
///   - `U.len() == (w/2) * (h/2)`
///   - `V.len() == (w/2) * (h/2)`
///
/// Strategy: for each 2×2 luma block, accumulate R/G/B across the four
/// pixels (2-bit right-shift average = sum>>2), then compute a single
/// chroma sample from that average.  This matches the "average RGB then
/// convert" path specified in the brief and avoids duplicate divisions.
///
/// # Panics
/// Panics if `rgb.len() != w * h * 3`.  `w` and `h` are silently rounded
/// down to even (the caller is expected to supply even dimensions).
pub fn rgb24_to_yuv420p(rgb: &[u8], w: usize, h: usize) -> (Vec<u8>, Vec<u8>, Vec<u8>) {
    let w = w & !1; // round down to even
    let h = h & !1;
    assert_eq!(
        rgb.len(),
        w * h * 3,
        "rgb24_to_yuv420p: buffer length mismatch (expected {}×{}×3={})",
        w,
        h,
        w * h * 3
    );

    let mut y_plane = vec![0u8; w * h];
    let mut u_plane = vec![0u8; (w / 2) * (h / 2)];
    let mut v_plane = vec![0u8; (w / 2) * (h / 2)];

    // BT.601 limited-range integer coefficients (×256 scaling):
    //   Y  =  16 + (65.738·R + 129.057·G +  25.064·B) / 256
    //   Cb = 128 + (-37.945·R -  74.494·G + 112.439·B) / 256
    //   Cr = 128 + (112.439·R -  94.154·G -  18.285·B) / 256
    //
    // Represented here as ×256 fixed-point integers (rounding to nearest):
    const KY_R: i32 = 66;   //  65.738  → 66
    const KY_G: i32 = 129;  // 129.057  → 129
    const KY_B: i32 = 25;   //  25.064  → 25

    const KU_R: i32 = -38;  // -37.945  → -38
    const KU_G: i32 = -74;  // -74.494  → -74
    const KU_B: i32 = 112;  // 112.439  → 112

    const KV_R: i32 = 112;  // 112.439  → 112
    const KV_G: i32 = -94;  // -94.154  → -94
    const KV_B: i32 = -18;  // -18.285  → -18

    #[inline(always)]
    fn clamp_u8(v: i32) -> u8 {
        v.clamp(0, 255) as u8
    }

    #[inline(always)]
    fn pixel_y(r: i32, g: i32, b: i32) -> u8 {
        clamp_u8(16 + (KY_R * r + KY_G * g + KY_B * b) / 256)
    }

    for row in 0..h {
        for col in 0..w {
            let base = (row * w + col) * 3;
            let r = rgb[base] as i32;
            let g = rgb[base + 1] as i32;
            let b = rgb[base + 2] as i32;
            y_plane[row * w + col] = pixel_y(r, g, b);
        }
    }

    // Chroma: one sample per 2×2 block — average the four RGB pixels first.
    for block_row in 0..(h / 2) {
        for block_col in 0..(w / 2) {
            let mut sum_r: i32 = 0;
            let mut sum_g: i32 = 0;
            let mut sum_b: i32 = 0;
            for dy in 0..2usize {
                for dx in 0..2usize {
                    let px_row = block_row * 2 + dy;
                    let px_col = block_col * 2 + dx;
                    let base = (px_row * w + px_col) * 3;
                    sum_r += rgb[base] as i32;
                    sum_g += rgb[base + 1] as i32;
                    sum_b += rgb[base + 2] as i32;
                }
            }
            // Integer average (sum of 4 → >>2)
            let avg_r = sum_r >> 2;
            let avg_g = sum_g >> 2;
            let avg_b = sum_b >> 2;

            let u = clamp_u8(128 + (KU_R * avg_r + KU_G * avg_g + KU_B * avg_b) / 256);
            let v = clamp_u8(128 + (KV_R * avg_r + KV_G * avg_g + KV_B * avg_b) / 256);

            let chroma_idx = block_row * (w / 2) + block_col;
            u_plane[chroma_idx] = u;
            v_plane[chroma_idx] = v;
        }
    }

    (y_plane, u_plane, v_plane)
}

// ─────────────────────────────────────────────────────────────────────────────
// PRIORITY 2 — H.264 4×4 integer DCT, zig-zag, quantisation
// ─────────────────────────────────────────────────────────────────────────────

/// H.264 4×4 zig-zag scan order (row-major block index → zig-zag position).
///
/// Index `i` gives the block position (0..15) that maps to zig-zag position
/// `i`.  Use this to reorder coefficient arrays before entropy coding.
pub const ZIGZAG4: [usize; 16] = [
    0,  1,  4,  8,
    5,  2,  3,  6,
    9, 12, 13, 10,
    7, 11, 14, 15,
];

/// H.264 core 4×4 integer forward DCT transform (ITU-T H.264 §8.5.12.1).
///
/// Input `blk` is a row-major 4×4 block of residual samples.
/// Returns the 4×4 block of *scaled* transform coefficients (the H.264
/// forward integer transform — note the result still contains the implicit
/// scaling factor Vf embedded by the standard; pass to `quant4x4` next).
pub fn fdct4x4(blk: &[i32; 16]) -> [i32; 16] {
    let mut w = [0i32; 16];

    // Horizontal pass (operate on rows)
    for row in 0..4 {
        let d = &blk[row * 4..row * 4 + 4];
        let e0 = d[0] + d[3];
        let e1 = d[1] + d[2];
        let e2 = d[1] - d[2];
        let e3 = d[0] - d[3];
        w[row * 4 + 0] = e0 + e1;
        w[row * 4 + 1] = (e3 << 1) + e2;  // 2*e3 + e2
        w[row * 4 + 2] = e0 - e1;
        w[row * 4 + 3] = e3 - (e2 << 1);  // e3 - 2*e2
    }

    let mut c = [0i32; 16];

    // Vertical pass (operate on columns)
    for col in 0..4 {
        let f0 = w[col] + w[12 + col];
        let f1 = w[4 + col] + w[8 + col];
        let f2 = w[4 + col] - w[8 + col];
        let f3 = w[col] - w[12 + col];
        c[col]      = f0 + f1;
        c[4 + col]  = (f3 << 1) + f2;
        c[8 + col]  = f0 - f1;
        c[12 + col] = f3 - (f2 << 1);
    }

    c
}

/// H.264 core 4×4 integer inverse DCT transform (ITU-T H.264 §8.5.12.2).
///
/// Input `c` is the scaled coefficient block (output of `dequant4x4`).
/// Returns a 4×4 block of residual samples (right-shifted by 6 per spec).
pub fn idct4x4(c: &[i32; 16]) -> [i32; 16] {
    let mut w = [0i32; 16];

    // Horizontal pass
    for row in 0..4 {
        let d = &c[row * 4..row * 4 + 4];
        let e0 = d[0] + d[2];
        let e1 = d[0] - d[2];
        let e2 = (d[1] >> 1) - d[3];
        let e3 = d[1] + (d[3] >> 1);
        w[row * 4 + 0] = e0 + e3;
        w[row * 4 + 1] = e1 + e2;
        w[row * 4 + 2] = e1 - e2;
        w[row * 4 + 3] = e0 - e3;
    }

    let mut out = [0i32; 16];

    // Vertical pass + rounding right-shift by 6
    for col in 0..4 {
        let f0 = w[col] + w[8 + col];
        let f1 = w[col] - w[8 + col];
        let f2 = (w[4 + col] >> 1) - w[12 + col];
        let f3 = w[4 + col] + (w[12 + col] >> 1);
        out[col]      = (f0 + f3 + 32) >> 6;
        out[4 + col]  = (f1 + f2 + 32) >> 6;
        out[8 + col]  = (f1 - f2 + 32) >> 6;
        out[12 + col] = (f0 - f3 + 32) >> 6;
    }

    out
}

// ─── H.264 quantisation / dequantisation ────────────────────────────────────
//
// H.264 spec §8.5.12.1 defines MF[i][j][qp%6] scaling matrices and a
// per-QP shift.  We use the standard 6-level MF table and the formula:
//
//   level[i] = (coeff[i] * MF + f) >> qbits       (forward quant)
//   coeff[i] = level[i] * V * (1 << (qp/6))        (inverse quant)
//
// For simplicity we use the flat (all-same-position) table entries:
//   MF values for positions (DC, edge, other) at each of the 6 QP phases.

/// Quantise a 4×4 block of forward-DCT coefficients for the given QP (0..51).
///
/// Uses H.264 integer quantisation with the standard MF scaling tables and
/// round-toward-zero (deadzone) rounding.  The sign of each coefficient is
/// preserved.
pub fn quant4x4(coeffs: &[i32; 16], qp: u8) -> [i32; 16] {
    let qp = qp.min(51) as usize;
    let qp_div6 = qp / 6;
    let qp_mod6 = qp % 6;

    // MF values indexed by [qp%6][position_class]
    // position_class: 0=corner(DC), 1=edge, 2=other
    // Source: ITU-T H.264 Table 8-15
    #[rustfmt::skip]
    const MF: [[i32; 3]; 6] = [
        [13107, 8066, 5243],
        [11916, 7490, 4660],
        [10082, 6554, 4194],
        [ 9362, 5825, 3647],
        [ 8192, 5243, 3355],
        [ 7282, 4559, 2893],
    ];

    // Position class for a 4×4 block (row-major index 0..15):
    //   corner  = (0,0),(0,2),(2,0),(2,2)  → indices 0,2,8,10
    //   edge    = (0,1),(0,3),(1,0),(1,2),(2,1),(2,3),(3,0),(3,2) → 1,3,4,6,9,11,12,14
    //   other   = the remaining 4 → 5,7,13,15
    #[rustfmt::skip]
    const POS_CLASS: [usize; 16] = [
        0, 1, 0, 1,
        1, 2, 1, 2,
        0, 1, 0, 1,
        1, 2, 1, 2,
    ];

    let qbits = 15 + qp_div6 as i32; // standard: 15 + floor(qp/6)
    let f = 1 << (qbits - 1);        // round-to-nearest (use f/3 for inter, f/2 for intra-ish)

    let mut out = [0i32; 16];
    for i in 0..16 {
        let mf = MF[qp_mod6][POS_CLASS[i]];
        let sign = coeffs[i].signum();
        let abs_c = coeffs[i].abs();
        out[i] = sign * ((abs_c * mf + f) >> qbits);
    }
    out
}

/// Dequantise a 4×4 block of quantised levels for the given QP (0..51).
///
/// Applies the H.264 inverse scaling:
///   `coeff = level * V[qp%6][pos] * (1 << (qp/6))`
pub fn dequant4x4(levels: &[i32; 16], qp: u8) -> [i32; 16] {
    let qp = qp.min(51) as usize;
    let qp_div6 = qp / 6;
    let qp_mod6 = qp % 6;

    // V scaling factors (inverse of MF), ITU-T H.264 Table 8-16
    #[rustfmt::skip]
    const V: [[i32; 3]; 6] = [
        [10, 16, 13],
        [11, 18, 14],
        [13, 20, 16],
        [14, 23, 18],
        [16, 25, 20],
        [18, 29, 23],
    ];

    #[rustfmt::skip]
    const POS_CLASS: [usize; 16] = [
        0, 1, 0, 1,
        1, 2, 1, 2,
        0, 1, 0, 1,
        1, 2, 1, 2,
    ];

    let shift = qp_div6 as i32;
    let mut out = [0i32; 16];
    for i in 0..16 {
        let v = V[qp_mod6][POS_CLASS[i]];
        out[i] = levels[i] * v * (1 << shift);
    }
    out
}

// ─────────────────────────────────────────────────────────────────────────────
// Tests
// ─────────────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    // ── P1: RGB→YUV ──────────────────────────────────────────────────────────

    fn solid_rgb(r: u8, g: u8, b: u8, w: usize, h: usize) -> Vec<u8> {
        let mut buf = Vec::with_capacity(w * h * 3);
        for _ in 0..w * h {
            buf.push(r);
            buf.push(g);
            buf.push(b);
        }
        buf
    }

    #[test]
    fn test_plane_lengths() {
        let w = 8usize;
        let h = 6usize;
        let rgb = solid_rgb(100, 100, 100, w, h);
        let (y, u, v) = rgb24_to_yuv420p(&rgb, w, h);
        assert_eq!(y.len(), w * h, "Y plane length");
        assert_eq!(u.len(), (w / 2) * (h / 2), "U plane length");
        assert_eq!(v.len(), (w / 2) * (h / 2), "V plane length");
    }

    #[test]
    fn test_black() {
        // RGB(0,0,0) → Y≈16, U≈128, V≈128
        let rgb = solid_rgb(0, 0, 0, 2, 2);
        let (y, u, v) = rgb24_to_yuv420p(&rgb, 2, 2);
        for &yv in &y { assert_eq!(yv, 16, "black Y"); }
        for &uv in &u { assert_eq!(uv, 128, "black U"); }
        for &vv in &v { assert_eq!(vv, 128, "black V"); }
    }

    #[test]
    fn test_white() {
        // RGB(255,255,255) → Y≈235
        let rgb = solid_rgb(255, 255, 255, 2, 2);
        let (y, u, v) = rgb24_to_yuv420p(&rgb, 2, 2);
        for &yv in &y {
            assert!(
                (230..=240).contains(&yv),
                "white Y out of range: got {}",
                yv
            );
        }
        // chroma should be near 128 for grey
        for &uv in &u { assert!((124..=132).contains(&uv), "white U: {}", uv); }
        for &vv in &v { assert!((124..=132).contains(&vv), "white V: {}", vv); }
    }

    #[test]
    fn test_red() {
        // RGB(255,0,0) → Y≈81, V≈240ish (Cr high), U below 128
        let rgb = solid_rgb(255, 0, 0, 2, 2);
        let (y, u, v) = rgb24_to_yuv420p(&rgb, 2, 2);
        for &yv in &y {
            assert!(
                (78..=85).contains(&yv),
                "red Y out of range: got {}",
                yv
            );
        }
        for &vv in &v {
            assert!(
                (230..=255).contains(&vv),
                "red V out of range: got {}",
                vv
            );
        }
        for &uv in &u {
            assert!(uv < 128, "red U should be < 128, got {}", uv);
        }
    }

    #[test]
    fn test_exact_y16_u128_v128_black() {
        let rgb = solid_rgb(0, 0, 0, 4, 4);
        let (y, u, v) = rgb24_to_yuv420p(&rgb, 4, 4);
        assert_eq!(y[0], 16);
        assert_eq!(u[0], 128);
        assert_eq!(v[0], 128);
    }

    // ── P2: DCT / quant round-trip ────────────────────────────────────────────

    #[test]
    fn test_zigzag_has_16_unique_indices() {
        let mut seen = [false; 16];
        for &idx in ZIGZAG4.iter() {
            assert!(idx < 16, "zigzag index out of range: {}", idx);
            assert!(!seen[idx], "duplicate zigzag index: {}", idx);
            seen[idx] = true;
        }
    }

    #[test]
    fn test_fdct_idct_zero_block() {
        let zero = [0i32; 16];
        let c = fdct4x4(&zero);
        let r = idct4x4(&c);
        assert_eq!(r, zero, "zero block round-trip");
    }

    #[test]
    fn test_idct_fdct_roundtrip_smooth_block() {
        // A smooth block (DC-dominant) should survive fdct→quant→dequant→idct
        // with small per-sample error (bounded by quantisation step size).
        let blk: [i32; 16] = [
            32, 30, 28, 26,
            30, 28, 26, 24,
            28, 26, 24, 22,
            26, 24, 22, 20,
        ];
        let qp: u8 = 20; // moderate QP
        let coeffs   = fdct4x4(&blk);
        let levels   = quant4x4(&coeffs, qp);
        let dequanted = dequant4x4(&levels, qp);
        let recon    = idct4x4(&dequanted);

        // Max per-sample error should be small for a smooth block at QP=20.
        // We allow ±8 which is generous but the test is about round-trip, not losslessness.
        for i in 0..16 {
            let err = (recon[i] - blk[i]).abs();
            assert!(
                err <= 8,
                "round-trip error too large at [{}]: orig={} recon={} err={}",
                i, blk[i], recon[i], err
            );
        }
    }

    #[test]
    fn test_quant_dequant_dc_only() {
        // A pure-DC block: all coefficients equal.  After quant/dequant the
        // DC coefficient (index 0) should dominate and AC should be small.
        let blk: [i32; 16] = [16; 16];
        let coeffs   = fdct4x4(&blk);
        let levels   = quant4x4(&coeffs, 10);
        let dequanted = dequant4x4(&levels, 10);
        let recon    = idct4x4(&dequanted);
        for i in 0..16 {
            let err = (recon[i] - blk[i]).abs();
            assert!(err <= 4, "DC round-trip err [{}]: orig={} recon={}", i, blk[i], recon[i]);
        }
    }

    #[test]
    fn test_white_y_value() {
        // Y for white should be ≤ 235 (limited range ceiling)
        let rgb = solid_rgb(255, 255, 255, 2, 2);
        let (y, _, _) = rgb24_to_yuv420p(&rgb, 2, 2);
        for &yv in &y {
            assert!(yv <= 235, "white Y exceeds limited-range ceiling: {}", yv);
        }
    }
}
